Great! Here are the steps to build a simple game with arrows:

1. Create a canvas on a webpage using HTML to display the game.
2. Load an image of a bow and arrow and position it on the canvas.
3. Create a target using shapes or an image and position it on the canvas.
4. Use JavaScript or a framework such as jQuery to handle user input for aiming and shooting the arrow.
5. When the user shoots, calculate the trajectory of the arrow based on its initial velocity and angle of release.
6. Calculate whether the arrow hit the target and display a message or score accordingly.

Here's some sample code to help you get started:

HTML:
```html
<canvas id="gameCanvas"></canvas>
```

JavaScript:
```javascript
var canvas = document.getElementById("gameCanvas");
var context = canvas.getContext("2d");

// Load images
var bowImg = new Image();
bowImg.src = "bow.png";
var arrowImg = new Image();
arrowImg.src = "arrow.png";
var target = {
    x: 100,
    y: 100,
    width: 50,
    height: 50
};
var arrow = {
    x: 0,
    y: 0,
    angle: 0,
    velocity: 10
};

function draw() {
    // Draw background
    context.fillStyle = "#FFFFFF";
    context.fillRect(0, 0, canvas.width, canvas.height);

    // Draw bow
    context.drawImage(bowImg, 50, canvas.height / 2 - bowImg.height / 2);

    // Draw target
    context.fillStyle = "#FF0000";
    context.fillRect(target.x, target.y, target.width, target.height);

    // Draw arrow
    context.save();
    context.translate(arrow.x, arrow.y);
    context.rotate(arrow.angle);
    context.drawImage(arrowImg, 0, -arrowImg.height / 2);
    context.restore();
}

document.addEventListener("mousemove", function(event) {
    // Calculate angle of bow
    var bowY = canvas.height / 2 - bowImg.height / 2;
    var deltaY = event.clientY - bowY;
    var angle = Math.atan2(deltaY, 50);
    bowImg.style.transform = "rotate(" + angle + "rad)";
});

document.addEventListener("mousedown", function(event) {
    // Calculate velocity and angle of arrow
    var angle = Math.atan2(event.clientY - canvas.height / 2, event.clientX - 50);
    arrow.angle = angle;
    arrow.velocity = Math.sqrt(Math.pow(event.clientX - 50, 2) + Math.pow(event.clientY - canvas.height / 2, 2)) / 10;
    arrow.x = 50;
    arrow.y = canvas.height / 2;
});

function update() {
    // Update arrow position
    arrow.x += Math.cos(arrow.angle) * arrow.velocity;
    arrow.y += Math.sin(arrow.angle) * arrow.velocity;

    // Check if arrow hit target
    if (arrow.x >= target.x && arrow.x <= target.x + target.width && arrow.y >= target.y && arrow.y <= target.y + target.height) {
        alert("You hit the target!");
    }
}

setInterval(function() {
    draw();
    update();
}, 30);
```

Note that this is just a basic example to get you started. You can obviously customize the game as you like, adding more features like multiple targets or obstacles.
